oxy_webhelp_navlinks = {"recover_oracle_databases-d30753e32674":{"topics":[{"title":"Database clones for Oracle","shortdesc":"<p class=\"shortdesc\">You can clone an Oracle database by selecting a recovery point to clone to a target     location.<\/p>","href":"oracle\/about_db_clones.html","attributes":{"data-id":"about_db_clones"},"menu":{"hasChildren":false},"tocID":"about_db_clones-d30753e32688","next":"about_db_clones-d30753e32688"},{"title":"Oracle Live Mount","shortdesc":"<p class=\"shortdesc\">An Oracle Live Mount creates a database from a point-in-time copy of the source     database to reduce the recovery time.<\/p>","href":"oracle\/oracle_live_mount.html","attributes":{"data-id":"oracle_live_mount"},"menu":{"hasChildren":false},"tocID":"oracle_live_mount-d30753e32765","next":"oracle_live_mount-d30753e32765"},{"title":"Advanced Oracle DB clone and mount parameters","shortdesc":"<p class=\"shortdesc\">A parameters file allows you to specify advanced recovery options for live mount and         cloning tasks.<\/p>","href":"oracle\/oracle_adv_clone_mount_params.html","attributes":{"data-id":"oracle_adv_clone_mount_params"},"menu":{"hasChildren":false},"tocID":"oracle_adv_clone_mount_params-d30753e32938","next":"oracle_adv_clone_mount_params-d30753e32938"},{"title":"Instant Recovery for Oracle","shortdesc":"<p class=\"shortdesc\">Instant Recovery for Oracle replaces an existing database with a point-in-time copy,     requiring specific configurations and directory setup.<\/p>","href":"oracle\/oracle_instant_recovery.html","attributes":{"data-id":"oracle_instant_recovery"},"menu":{"hasChildren":false},"tocID":"oracle_instant_recovery-d30753e32982","next":"oracle_instant_recovery-d30753e32982"},{"title":"Same Host Recovery","shortdesc":"<p class=\"shortdesc\">Recover a database to the source Oracle host or Oracle RAC.<\/p>","href":"oracle\/samehost_recover.html","attributes":{"data-id":"about_samehost_recover"},"menu":{"hasChildren":false},"tocID":"about_samehost_recover-d30753e33018","next":"about_samehost_recover-d30753e33018"},{"title":"Downloading an archived Oracle database snapshot","shortdesc":"<p class=\"shortdesc\">Recover an Oracle database snapshot that is no longer stored on the local cluster but         remains available in an archival location.<\/p>","href":"oracle\/downloading_archived_oracle_db_snapshot.html","attributes":{"data-id":"downloading_archived_oracle_db_snapshot"},"menu":{"hasChildren":false},"tocID":"downloading_archived_oracle_db_snapshot-d30753e33062","topics":[]},{"title":"Recovering an Oracle database from a replica","shortdesc":"<p class=\"shortdesc\">Recover an Oracle database from a replicated snapshot of the database stored on         another Rubrik cluster.<\/p>","href":"oracle\/recovering_oracle_database_replica.html","attributes":{"data-id":"recovering_oracle_database_replica"},"menu":{"hasChildren":false},"tocID":"recovering_oracle_database_replica-d30753e33073","topics":[]},{"title":"Recovery from RAC to standalone Oracle hosts","shortdesc":"<p class=\"shortdesc\">For <span class=\"ph\">RSC<\/span> running Rubrik CDM version 9.2 or later, you can perform live         mounts or clones of Oracle RAC snapshots to an Oracle standalone host.<\/p>","href":"oracle\/recovery_rac_standalone_oracle_hosts.html","attributes":{"data-id":"recovery_rac_standalone_oracle_hosts"},"menu":{"hasChildren":false},"tocID":"recovery_rac_standalone_oracle_hosts-d30753e33084","topics":[]},{"title":"Recovery to a secondary Oracle host","shortdesc":"<p class=\"shortdesc\">You can add a secondary Oracle host to a Rubrik cluster to provide more target options     for snapshot recovery.<\/p>","href":"oracle\/recovery_secondary_oracle_host.html","attributes":{"data-id":"recovery_secondary_oracle_host"},"menu":{"hasChildren":false},"tocID":"recovery_secondary_oracle_host-d30753e33098","topics":[]},{"title":"Point-in-time recovery","shortdesc":"<p class=\"shortdesc\">Point-in-time recovery uses database snapshots and their associated logs to restore a     database to its state at a specific point in time.<\/p>","href":"oracle\/point-in-time_recovery.html","attributes":{"data-id":"point-in-time_recovery"},"menu":{"hasChildren":false},"tocID":"point-in-time_recovery-d30753e33109","topics":[]},{"title":"Number of channels in recovery","shortdesc":"<p class=\"shortdesc\">The value for the number of channels in recovery can be configured for Live Mount,         Clone, Restore, Instant Recovery, and Validation operations.<\/p>","href":"oracle\/number_of_channels_in_recovery.html","attributes":{"data-id":"number_of_channels_in_recovery"},"menu":{"hasChildren":false},"tocID":"number_of_channels_in_recovery-d30753e33121","topics":[]},{"title":"Oracle recovery using SCNs","shortdesc":"<p class=\"shortdesc\">You can recover Oracle snapshots and mount archive logs using the system change         number instead of the date and time when the snapshot occurs, providing a more accurate         point of recovery.<\/p>","href":"oracle\/oracle_recovery_using_scns.html","attributes":{"data-id":"oracle_recovery_using_scns"},"menu":{"hasChildren":false},"tocID":"oracle_recovery_using_scns-d30753e33132","next":"oracle_recovery_using_scns-d30753e33132"},{"title":"Advanced Cloning Operations and custom PFILES","shortdesc":"<p class=\"shortdesc\">You can use the Advanced Cloning Operations or a custom PFILE options when you         require the target recovery operation to use a different configuration than the source         database backup.<\/p>","href":"oracle\/aco_custom_pfiles.html","attributes":{"data-id":"aco_custom_pfiles"},"menu":{"hasChildren":false},"tocID":"aco_custom_pfiles-d30753e33187","next":"aco_custom_pfiles-d30753e33187"},{"title":"Tablespace recovery","shortdesc":"<p class=\"shortdesc\">Restore a tablespace in place to the same database.<\/p>","href":"oracle\/tablespace_recovery.html","attributes":{"data-id":"tablespace_recovery"},"menu":{"hasChildren":false},"tocID":"tablespace_recovery-d30753e33220","next":"tablespace_recovery-d30753e33220"}]}};